import { HttpError } from 'wasp/server';

export const onBeforeSignup = async (args: { providerUserId: string }) => {
  const { providerUserId } = args;

  // Check if the username contains "blocked"
  if (providerUserId.toLowerCase().includes('blocked')) {
    throw new HttpError(403, 'This username is not allowed.');
  }
};

import { useAuth } from 'wasp/client/auth';
import { logout } from 'wasp/client/auth';

export function MainPage() {
  const { data: user } = useAuth();

  return (
    <main className="container">
      <h2 className="title">Welcome {user?.username}!</h2>

      <p className="content">
        This is a protected page. You are logged in as <code>{user?.username}</code>.
      </p>

      <button onClick={logout} className="button button-filled">
        Logout
      </button>
    </main>
  );
}

